// MARK: - Transaction Processor
class TransactionProcessor {
    static let shared = TransactionProcessor()
    
    private init() {}
    
    func processTransaction(_ transaction: Transaction, account: Account) -> Result<Account, TransactionError> {
        // Validate transaction
        guard validateTransaction(transaction) else {
            return .failure(.invalidTransaction)
        }
        
        // Process based on transaction type
        switch transaction.type {
        case .deposit:
            return .success(updateBalance(account, by: transaction.amount))
        case .withdrawal:
            guard account.balance >= transaction.amount else {
                return .failure(.insufficientFunds)
            }
            return .success(updateBalance(account, by: -transaction.amount))
        case .transfer:
            guard account.balance >= transaction.amount else {
                return .failure(.insufficientFunds)
            }
            return .success(updateBalance(account, by: -transaction.amount))
        case .payment:
            guard account.balance >= transaction.amount else {
                return .failure(.insufficientFunds)
            }
            return .success(updateBalance(account, by: -transaction.amount))
        }
    }
    
    private func validateTransaction(_ transaction: Transaction) -> Bool {
        return transaction.amount > 0 && !transaction.description.isEmpty
    }
    
    private func updateBalance(_ account: Account, by amount: Double) -> Account {
        return Account(
            id: account.id,
            accountNumber: account.accountNumber,
            balance: account.balance + amount,
            accountType: account.accountType,
            currency: account.currency,
            createdAt: account.createdAt
        )
    }
}

// MARK: - Transaction Error
enum TransactionError: Error, LocalizedError {
